#include <stdlib.h>
#include <iostream>
#include <sstream>
#include <string>
#include <chrono>
#include <Displays.h>

using namespace std;

void exec_msg(){
	cerr << "Usage: ./GenerateYAML4ACE NumberOfBlock \"Species\" rcut K NRad1 NRad.. NRadK L2 L.. LK (Lint4 Lint5) OutputFilename" << endl;
	cerr << "This executable allows to generate a yaml file containing the informations for computing ACE descriptors." << endl;
	cerr << "It allows to specify for each combination of atomic species the parameters of the descriptors." << endl;
	cerr << "The created yaml file can then be used to compute ACE descriptors using the ComputeDescriptors executable" << endl;
	cerr << "The \"Species rcut K NRad1 NRad.. NRadK L1 L.. LK (Lint)\" parameters constitute a speciesblock for a given combination of specie(s). The number of provided speciesblock should be given as a first argument of the executable (NumberOfBlock). For each set of parameters, a new speciesblock section will be added to the output yaml file" << endl;
	cerr << " - \"Species\": the quote must be used for providing species, examples : \"Al\", \"Al O\", \"Al Mg O\", etc." << endl;
	cerr << " - K: interaction rank for this block (1 => 2-body, 2 => 2-body + 3-body, 3 => 2-body + 3-body + 4-body, etc. with maximum of 6-body interaction)" << endl;	
	cerr << " - rcut: cutoff radius (rcut should be equal for blocks containing the same species, e.g. \"Mg O\" and \"O Mg\" shoudl have the same cutoff radius)" << endl; 
	cerr << " - NRad1 NRad.. NRadK: maximum order of radial functions used for N-body descriptors (K values must be provided), NRad4 has a maximum value of 3 while NRad5 has a maximum value of 2" << endl;
	cerr << " - L2 L.. LK : maximum order of spherical harmonics used for N-body descriptors (K-1 values must be provided as L is always 0 for 2-body interactions), L4 has a maximum value of 3 while L5 has a maximum value of 2" << endl;
	cerr << " - Lint4 Lint5 : maximum degree of spherical harmonics for 5 and 6-body descriptors (it means that Lint should only be provided if K >= 4), Lint4 has a maximum value of 3 while Lint5 has a maximum value of 2" << endl;
	cerr << "Total number of descriptors can be decrease by removing lines in the nbody section" << endl;
}

void GetNonZeroRank4(vector<unsigned int> &keepOrNot, vector<unsigned int> &dims5body);
void GetNonZeroRank5(vector<unsigned int> &keepOrNot, vector<unsigned int> &dims6body);

int main(int argc, char *argv[])
{
	Displays Dis;
	Dis.Logo();
	if( argc == 0 || argc < 7 ){
		exec_msg();
		return EXIT_FAILURE;
	}

	unsigned int nbblock;

	string OutputFilename;

	unsigned int current_read_ind = 1;
	
	istringstream iss_nbblock(argv[current_read_ind]);
	iss_nbblock >> nbblock;
	current_read_ind++;
	
	vector<vector<string>> species(nbblock);
	vector<double> rcut(nbblock);
        vector<unsigned int> Rank(nbblock);
	vector<vector<unsigned int>> NRad(nbblock), L(nbblock), Lint(nbblock);
	unsigned int maxNRad1(0), maxNRadK(0), maxL(0);
	
	double buffer_d;
	unsigned int buffer_uint;
	string buffer_s;
	
	bool Rank4 = false;
	bool Rank5 = false;

	for(unsigned int b=0;b<nbblock;b++){
		buffer_s = argv[current_read_ind];
		istringstream spe(buffer_s);
		while( spe >> buffer_s ) species[b].push_back(buffer_s);
		current_read_ind++;

		istringstream iss_rc(argv[current_read_ind]);
		iss_rc >> buffer_d;
		rcut[b] = buffer_d;
		current_read_ind++;
		
		istringstream iss_rank(argv[current_read_ind]);
		iss_rank >> buffer_uint;
		Rank[b] = buffer_uint;
		current_read_ind++;

		istringstream iss_nrad1(argv[current_read_ind]);
		iss_nrad1 >> buffer_uint;
		NRad[b].push_back(buffer_uint);
		current_read_ind++;
		if( buffer_uint > maxNRad1 ) maxNRad1 = buffer_uint;
		for(unsigned int n=1;n<Rank[b];n++){
			istringstream iss_nrad(argv[current_read_ind]);
			iss_nrad >> buffer_uint;
			NRad[b].push_back(buffer_uint);
			current_read_ind++;
			if( buffer_uint > maxNRadK ) maxNRadK = buffer_uint;
		}
	
		L[b].push_back(0);	
		for(unsigned int n=1;n<Rank[b];n++){
			istringstream iss_l(argv[current_read_ind]);
			iss_l >> buffer_uint;
			L[b].push_back(buffer_uint);
			current_read_ind++;
			if( buffer_uint > maxL ) maxL = buffer_uint;
		}

		if( Rank[b] >= 4 ){
			for(unsigned int n=3;n<Rank[b];n++){
				istringstream iss_lint(argv[current_read_ind]);
				iss_lint >> buffer_uint;
				Lint[b].push_back(buffer_uint);
				current_read_ind++;
			}
		}
		
		cout << "Block " << b+1 << ": ";
		for(unsigned int i=0;i<species[b].size();i++) cout << species[b][i] << " ";
		cout << ", rcut = " << rcut[b] << ", rank = " << Rank[b] << ", NRad = [" << NRad[b][0];
		for(unsigned int n=1;n<Rank[b];n++) cout << ", " << NRad[b][n];
		cout << "], l = [0";
		for(unsigned int n=1;n<Rank[b];n++) cout << ", " << L[b][n];
		cout << "]";
		if( Rank[b] >= 4 ){
			Rank4 = true;
			cout << ", lint = [" << Lint[b][0];
		        if( Rank[b] == 5 ){
				cout << ", " << Lint[b][1];
				Rank5 = true;
			}
		        cout << "]";
		}
	        cout << endl;
	}
	
	OutputFilename = argv[current_read_ind];
	ofstream writefile(OutputFilename);

	// Get non zero vectors if rank is higher than 4 and 5
	vector<unsigned int> KeepOrNot5body, dims5body;
	vector<unsigned int> KeepOrNot6body, dims6body;
	if( Rank4 ) GetNonZeroRank4(KeepOrNot5body,dims5body);
	if( Rank5 ) GetNonZeroRank5(KeepOrNot6body,dims6body);

	// write header
	writefile << "# file generated using ./GenerateYAML4ACE ";
	writefile << nbblock << " ";
	for(unsigned int b=0;b<nbblock;b++){
		writefile << "\"" << species[b][0];
		for(unsigned int i=1;i<species[b].size();i++) writefile << " " << species[b][i];
		writefile << "\" " << rcut[b] << " " << Rank[b] << "  ";
		for(unsigned int n=0;n<Rank[b];n++) writefile << NRad[b][n] << " ";
		writefile << " ";
		for(unsigned int n=1;n<Rank[b];n++) writefile << L[b][n] << " ";
		if( Rank[b] >= 4 ){
			writefile << " " << Lint[b][0] << " ";
		        if( Rank[b] == 5 ) writefile << Lint[b][1] << " ";
			writefile << " ";
		}
	}
	writefile << endl;

	// write the core of yaml file
	writefile << "global:" << endl;
	writefile << "  DeltaSplineBins: 0.001" << endl;
	writefile << "species:" << endl;
	for(unsigned int b=0;b<nbblock;b++){
		unsigned int nbDims = 0;
		unsigned int nbspec = species[b].size();
		writefile << "  - speciesblock: ";
		for(unsigned int s=0;s<nbspec;s++) writefile << species[b][s] << " ";
	        writefile << endl;
		writefile << "    ndensityi: 0" << endl;
		writefile << "    npoti: " << endl;
		writefile << "    parameters: []" << endl;
		writefile << "    nradmaxi: " << maxNRadK << endl;
		writefile << "    lmaxi: " << maxL << endl;
		writefile << "    rcutij: " << rcut[b] << endl;
		writefile << "    dcutij: 0.01 # does not impact values of descriptors" << endl;
		writefile << "    nradbaseij: " << maxNRad1 << endl;
		writefile << "    radbase: SBessel" << endl;
		writefile << "    radparameters: [1.] # does not impact values of descriptors" << endl;
		writefile << "    radcoefficients: [";
		for(unsigned int i=0;i<maxNRadK;i++){
			writefile << "[";
			for(unsigned int j=0;j<maxL+1;j++){
				writefile << "[";
				for(unsigned int k=0;k<maxNRad1;k++){
					if( i == k ) writefile << "1.";
					else writefile << "0.";
					if( k != maxNRad1-1 ) writefile << ", ";
				}
				writefile << "]";
				if( j != maxL ) writefile << ", ";
			}
			writefile << "]";
			if( i+1 != maxNRadK ) writefile << ", ";
		}
		writefile << "]" << endl;
		writefile << "    nbody:" << endl;
		// 2-body
		if( nbspec <= 2 && Rank[b] >= 1 ){
			for(unsigned int i=0;i<NRad[b][0];i++){
				writefile << "      - {type:";
				for(unsigned int s=0;s<nbspec;s++) writefile << " " << species[b][s];
				if( nbspec == 1 ) writefile << " " << species[b][0]; 
				writefile << ", nr: [" << i+1 << "], nl: [0]}" << endl;
				nbDims++;
			}
		}
		// 3-body
		if( Rank[b] >= 2 && nbspec <= 3 ){
			vector<string> spec_comb;
			if( nbspec == 1 ) spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][0]);
			else if( nbspec == 3 ) spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]);
			else{
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][1]);
			}
			for(unsigned int s=0;s<spec_comb.size();s++){
				for(unsigned int nr1=0;nr1<NRad[b][1];nr1++){
					for(unsigned int nr2=nr1;nr2<NRad[b][1];nr2++){
						for(unsigned int l=0;l<L[b][1]+1;l++){
							writefile << "      - {type: " << spec_comb[s];
							writefile << ", nr: [" << nr1+1 <<", " << nr2+1 << "], nl: [" << l << ", " << l << "]}" << endl;
							nbDims++;
						}
					}
				}
			}
		}
		// 4-body
		if( Rank[b] >= 3 && nbspec <= 4 ){
			vector<string> spec_comb;
			if( nbspec == 1 ) spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][0]);
			else if( nbspec == 2 ){
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][1]);
			}else if( nbspec == 3 ){
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][2]);
			}else spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]);
			vector<vector<unsigned int>> combs3;
			for(unsigned int d1=0;d1<3;d1++){
				for(unsigned int d2=0;d2<3;d2++){
					for(unsigned int d3=0;d3<3;d3++){
						if( d1 != d2 && d1 != d3 && d2 != d3 ){
							combs3.push_back(vector<unsigned int>());
							combs3[combs3.size()-1].push_back(d1);
							combs3[combs3.size()-1].push_back(d2);
							combs3[combs3.size()-1].push_back(d3);
						}
					}
				}
			}
			for(unsigned int s=0;s<spec_comb.size();s++){
				for(unsigned int nr1=0;nr1<NRad[b][2];nr1++){
					for(unsigned int nr2=nr1;nr2<NRad[b][2];nr2++){
						for(unsigned int nr3=nr2;nr3<NRad[b][2];nr3++){
							vector<unsigned int> true_nr;
							true_nr.push_back(nr1+1);
							true_nr.push_back(nr2+1);
							true_nr.push_back(nr3+1);
							vector<vector<unsigned int>> lcombs;
							for(unsigned int l1=0;l1<L[b][2]+1;l1++){
								for(unsigned int l2=l1;l2<L[b][2]+1;l2++){
									unsigned int l3_min = abs((int)l1 - (int)l2);// |l1-l2| <= l3 <= l1+l2 from PRB paper
            								unsigned int l3_max = l1 + l2;
									if(l3_max >= L[b][2]) l3_max = L[b][2];
									for(unsigned int l3=l3_min;l3<=l3_max;l3++){
										if( (l1+l2+l3)%2 == 0 ){
										       bool already = false;
										       vector<unsigned int> current_l;
										       current_l.push_back(l1*true_nr[0]);
										       current_l.push_back(l2*true_nr[1]);
										       current_l.push_back(l3*true_nr[2]);
										       for(unsigned int a=0;a<lcombs.size();a++){
											       for(unsigned int d=0;d<combs3.size();d++){
												       if( current_l[0] == lcombs[a][combs3[d][0]]*true_nr[combs3[d][0]] && current_l[1] == lcombs[a][combs3[d][1]]*true_nr[combs3[d][1]] && current_l[2] == lcombs[a][combs3[d][2]]*true_nr[combs3[d][2]] ){
												       		already = true;
												       		break;
												       }
											       }
											       if( already ) break;
										       }
										       if( !already ){
											       lcombs.push_back(vector<unsigned int>());
											       lcombs[lcombs.size()-1].push_back(l1);
											       lcombs[lcombs.size()-1].push_back(l2);
											       lcombs[lcombs.size()-1].push_back(l3);
										       }
										}
									}
								}
							}
							for(unsigned int a=0;a<lcombs.size();a++){
								writefile << "      - {type: " << spec_comb[s];
								writefile << ", nr: [" << nr1+1 <<", " << nr2+1 << ", " << nr3+1 << "], nl: [" << lcombs[a][0] << ", " << lcombs[a][1] << ", " << lcombs[a][2] << "], lint: [" << lcombs[a][2] << "]}" << endl;
								nbDims++;
							}
						}
					}
				}
			}
		}

		// 5-body
		if( Rank[b] >= 4 && nbspec <= 5 ){
			vector<string> spec_comb;
			if( nbspec == 1 ) spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][0]);
			else if( nbspec == 2 ){
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][1]);
			}else if( nbspec == 3 ){
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][2]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][2]+" "+species[b][2]);
			}else if( nbspec == 4 ){
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][0]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][3]);
			}else spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][4]);

			vector<vector<unsigned int>> combs4;
			for(unsigned int d1=0;d1<4;d1++){
				for(unsigned int d2=0;d2<4;d2++){
					for(unsigned int d3=0;d3<4;d3++){
						for(unsigned int d4=0;d4<4;d4++){
							if( d1 != d2 && d1 != d3 && d1 != d4 && d2 != d3 && d2 != d4 && d3 != d4 ){
								combs4.push_back(vector<unsigned int>());
								combs4[combs4.size()-1].push_back(d1);
								combs4[combs4.size()-1].push_back(d2);
								combs4[combs4.size()-1].push_back(d3);
								combs4[combs4.size()-1].push_back(d4);
							}
						}
					}
				}
			}

			for(unsigned int s=0;s<spec_comb.size();s++){
				for(unsigned int nr1=0;nr1<NRad[b][3];nr1++){
					for(unsigned int nr2=nr1;nr2<NRad[b][3];nr2++){
						for(unsigned int nr3=nr2;nr3<NRad[b][3];nr3++){
							for(unsigned int nr4=nr3;nr4<NRad[b][3];nr4++){
								vector<unsigned int> true_nr;
								true_nr.push_back(nr1+1);
								true_nr.push_back(nr2+1);
								true_nr.push_back(nr3+1);
								true_nr.push_back(nr4+1);
								vector<vector<unsigned int>> lcombs;
								for(unsigned int l1=0;l1<L[b][3]+1;l1++){
									for(unsigned int l2=0;l2<L[b][3]+1;l2++){
										for(unsigned int l3=0;l3<L[b][3]+1;l3++){
											for(unsigned int l4=0;l4<L[b][3]+1;l4++){
												if( (l1+l2+l3+l4)%2 == 0 ){

											       		bool already = false;
											       		vector<unsigned int> current_l;
											       		current_l.push_back(l1*true_nr[0]);
											       		current_l.push_back(l2*true_nr[1]);
											       		current_l.push_back(l3*true_nr[2]);
											       		current_l.push_back(l4*true_nr[3]);
											       		for(unsigned int a=0;a<lcombs.size();a++){
											       		        for(unsigned int d=0;d<combs4.size();d++){
											       		 	       if( current_l[0] == lcombs[a][combs4[d][0]]*true_nr[combs4[d][0]] && current_l[1] == lcombs[a][combs4[d][1]]*true_nr[combs4[d][1]] && current_l[2] == lcombs[a][combs4[d][2]]*true_nr[combs4[d][2]] && current_l[3] == lcombs[a][combs4[d][3]]*true_nr[combs4[d][3]] ){
											       		 	       		already = true;
											       		 	       		break;
											       		 	       }
											       		        }
											       		        if( already ) break;
											       		}
											       		if( !already ){
											       		        lcombs.push_back(vector<unsigned int>());
											       		        lcombs[lcombs.size()-1].push_back(l1);
											       		        lcombs[lcombs.size()-1].push_back(l2);
											       		        lcombs[lcombs.size()-1].push_back(l3);
											       		        lcombs[lcombs.size()-1].push_back(l4);

														for(unsigned int lint=0;lint<Lint[b][0]+1;lint++){
															unsigned int index = lint + dims5body[0]*l4 + dims5body[1]*l3 + dims5body[2]*l2 + dims5body[3]*l1 + dims5body[4]*nr4 + dims5body[5]*nr3 + dims5body[6]*nr2 + dims5body[7]*nr1;
														        if( KeepOrNot5body[index] == 1 ){	
																writefile << "      - {type: " << spec_comb[s];
																writefile << ", nr: [" << nr1+1 <<", " << nr2+1 << ", " << nr3+1 << ", " << nr4+1 << "], nl: [" << l1 << ", " << l2 << ", " << l3 << ", " << l4 << "], lint: [" << lint << ", " << lint << "]}" << endl;
																nbDims++;
															}
														}
											       		}
												}
											}
										}
									}
								}
							}
						}
					}
				}
			}
		}
		// 6-body
		if( Rank[b] >= 5 && nbspec <= 6 ){
			vector<string> spec_comb;
			if( nbspec == 1 ) spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][0]);
			else if( nbspec == 2 ){
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][1]);
			}else if( nbspec == 3 ){
				spec_comb.push_back(species[b][0]+" "+species[b][2]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][2]+" "+species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][2]+" "+species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][2]+" "+species[b][0]+" "+species[b][0]+" "+species[b][0]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][2]+" "+species[b][2]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][0]+" "+species[b][2]+" "+species[b][2]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][0]+" "+species[b][0]+" "+species[b][2]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][2]+" "+species[b][2]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][1]+" "+species[b][2]+" "+species[b][2]);
			}else if( nbspec == 4 ){
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][0]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][3]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][3]);
				spec_comb.push_back(species[b][0]+" "+species[b][2]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][2]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][3]);
				spec_comb.push_back(species[b][0]+" "+species[b][3]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][3]);
			}else if( nbspec == 5 ){
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][4]+" "+species[b][0]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][4]+" "+species[b][1]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][4]+" "+species[b][2]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][4]+" "+species[b][3]);
				spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][4]+" "+species[b][4]);
			}else spec_comb.push_back(species[b][0]+" "+species[b][1]+" "+species[b][2]+" "+species[b][3]+" "+species[b][4]+" "+species[b][5]);
	
			vector<vector<unsigned int>> combs5;
			for(unsigned int d1=0;d1<5;d1++){
				for(unsigned int d2=0;d2<5;d2++){
					for(unsigned int d3=0;d3<5;d3++){
						for(unsigned int d4=0;d4<5;d4++){
							for(unsigned int d5=0;d5<5;d5++){
								if( d1 != d2 && d1 != d3 && d1 != d4 && d1 != d5 && d2 != d3 && d2 != d4 && d2 != d5 && d3 != d4 && d3 != d5 && d4 != d5 ){
									combs5.push_back(vector<unsigned int>());
									combs5[combs5.size()-1].push_back(d1);
									combs5[combs5.size()-1].push_back(d2);
									combs5[combs5.size()-1].push_back(d3);
									combs5[combs5.size()-1].push_back(d4);
									combs5[combs5.size()-1].push_back(d5);
								}
							}
						}
					}
				}
			}
			for(unsigned int s=0;s<spec_comb.size();s++){
				for(unsigned int nr1=0;nr1<NRad[b][4];nr1++){
					for(unsigned int nr2=nr1;nr2<NRad[b][4];nr2++){
						for(unsigned int nr3=nr2;nr3<NRad[b][4];nr3++){
							for(unsigned int nr4=nr3;nr4<NRad[b][4];nr4++){
								for(unsigned int nr5=nr4;nr5<NRad[b][4];nr5++){
									vector<unsigned int> true_nr;
									true_nr.push_back(nr1+1);
									true_nr.push_back(nr2+1);
									true_nr.push_back(nr3+1);
									true_nr.push_back(nr4+1);
									true_nr.push_back(nr5+1);
									vector<vector<unsigned int>> lcombs;
									for(unsigned int l1=0;l1<L[b][4]+1;l1++){
										for(unsigned int l2=0;l2<L[b][4]+1;l2++){
											for(unsigned int l3=0;l3<L[b][4]+1;l3++){
												for(unsigned int l4=0;l4<L[b][4]+1;l4++){
													for(unsigned int l5=0;l5<L[b][4]+1;l5++){
														if( (l1+l2+l3+l4+l5)%2 == 0 ){

											       				bool already = false;
											       				vector<unsigned int> current_l;
											       				current_l.push_back(l1*true_nr[0]);
											       				current_l.push_back(l2*true_nr[1]);
											       				current_l.push_back(l3*true_nr[2]);
											       				current_l.push_back(l4*true_nr[3]);
											       				current_l.push_back(l5*true_nr[4]);
											       				for(unsigned int a=0;a<lcombs.size();a++){
											       				        for(unsigned int d=0;d<combs5.size();d++){
											       				 	       if( current_l[0] == lcombs[a][combs5[d][0]]*true_nr[combs5[d][0]] && current_l[1] == lcombs[a][combs5[d][1]]*true_nr[combs5[d][1]] && current_l[2] == lcombs[a][combs5[d][2]]*true_nr[combs5[d][2]] && current_l[3] == lcombs[a][combs5[d][3]]*true_nr[combs5[d][3]] && current_l[4] == lcombs[a][combs5[d][4]]*true_nr[combs5[d][4]] ){
											       				 	       		already = true;
											       				 	       		break;
											       				 	       }
											       				        }
											       				        if( already ) break;
											       				}
											       				if( !already ){
											       				        lcombs.push_back(vector<unsigned int>());
											       				        lcombs[lcombs.size()-1].push_back(l1);
											       				        lcombs[lcombs.size()-1].push_back(l2);
											       				        lcombs[lcombs.size()-1].push_back(l3);
											       				        lcombs[lcombs.size()-1].push_back(l4);
											       				        lcombs[lcombs.size()-1].push_back(l5);

																for(unsigned int lint1=0;lint1<Lint[b][1]+1;lint1++){
																	for(unsigned int lint2=0;lint2<Lint[b][1]+1;lint2++){

																		unsigned int index = lint2 + lint1*dims6body[0] + l5*dims6body[1] +dims6body[2]*l4 + dims6body[3]*l3 + dims6body[4]*l2 + dims6body[5]*l1 + dims6body[6]*nr5 + dims6body[7]*nr4 + dims6body[8]*nr3 + dims6body[9]*nr2 + dims6body[10]*nr1;
														        			if( KeepOrNot6body[index] == 1 ){	
																			writefile << "      - {type: " << spec_comb[s];
																			writefile << ", nr: [" << nr1+1 <<", " << nr2+1 << ", " << nr3+1 << ", " << nr4+1 << ", " << nr5+1 << "], nl: [" << l1 << ", " << l2 << ", " << l3 << ", " << l4 << ", " << l5 << "], lint: [" << lint1 << ", " << lint2 << ", " << l5 << "]}" << endl;
																			nbDims++;
																		}
																	}
																}
															}
														}
													}
												}
											}
										}
									}
								}
							}
						}
					}
				}
			}
		} // end 6-body
		cout << "Block " << b+1 << " (";
		for(unsigned int s=0;s<nbspec-1;s++) cout << species[b][s] << " ";
		cout << species[b][nbspec-1] << ") will lead to " << nbDims << "-dimension ACE descriptors" << endl; 

	}
	cout << endl << "File " << OutputFilename << " successfully writted !" << endl;
	Dis.ExecutionTime();
	// parameters having default values :
	// - r_in: 0
	// to continue	
	return 0;
}

